// ============= Build =============
const QUESTIONS_PATH = path.join(__dirname, 'data', 'questions.json');

function ensureN(arr, n) {
  const result = [];
  for (let i = 0; i < n; i++) {
    const item = { ...arr[i % arr.length], id: nid() };
    result.push(item);
  }
  return result;
}

